parameters.jsonBody:
={{ JSON.stringify({ model: 'llama3:8b', prompt: `Analyze the following meeting transcript and produce a structured summary.

Meeting: ${$json.meeting_title}
Attendees: ${$json.attendees}

Transcript:
${$json.transcript}

Return a JSON object with these fields:
- summary: 3-5 sentence overview of the meeting
- key_decisions: array of decisions made
- action_items: array of objects with fields: task, owner, deadline
- follow_ups: array of items that need follow-up
- topics_discussed: array of main topics

Return ONLY valid JSON, no markdown.`, stream: false, options: { temperature: 0.3 } }) }}

parameters.jsCode:
const response = $input.first().json.response;

// Try to parse JSON from Ollama response
let parsed;
try {
  const jsonMatch = response.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch[0]);
} catch (e) {
  parsed = {
    summary: response,
    key_decisions: [],
    action_items: [],
    follow_ups: [],
    topics_discussed: []
  };
}

return [{ json: parsed }];

parameters.jsonBody:
={{ JSON.stringify({ model: 'llama3:8b', prompt: `Based on these meeting action items, write a brief follow-up email that could be sent to all attendees.

Meeting Summary: ${$json.summary}

Action Items:
${JSON.stringify($json.action_items)}

Key Decisions:
${JSON.stringify($json.key_decisions)}

Write a professional, concise follow-up email. Include all action items with owners and deadlines. Keep it under 200 words.`, stream: false, options: { temperature: 0.4 } }) }}
